+      call_id: "call_turn1",
+      id: "fc_turn1",
+    });
+  });
+
+  it("uses full context on the initial turn", () => {
+    const context = {
+      systemPrompt: "You are helpful.",
+      messages: [userMsg("Hello!")] as Parameters<typeof convertMessagesToInputItems>[0],
